class ProductSerializer(serializers.ModelSerializer):
    """Detailed product serializer."""
    category = CategorySerializer(read_only=True)
    average_rating = serializers.SerializerMethodField()
    review_count = serializers.SerializerMethodField()

    class Meta:
        model = Product
        fields = [
            'id', 'name', 'slug', 'description', 'price',
            'stock', 'is_active', 'is_featured', 'sku',
            'weight', 'category', 'average_rating',
            'review_count', 'created_at', 'updated_at'
        ]
        read_only_fields = ['id', 'created_at', 'updated_at']

    def get_average_rating(self, obj):
        # Assuming Product has a related Rating model
        return obj.ratings.aggregate(Avg('score'))['score__avg'] or 0

    def get_review_count(self, obj):
        return obj.ratings.count()

class ProductCreateSerializer(serializers.ModelSerializer):
    """Serializer for creating/updating products."""
    category_id = serializers.PrimaryKeyRelatedField(
        queryset=Category.objects.all(),
        source='category',
        required=False,
        allow_null=True
    )

    class Meta:
        model = Product
        fields = [
            'name', 'slug', 'description', 'price',
            'stock', 'is_active', 'is_featured',
            'sku', 'weight', 'category_id'
        ]

    def validate_sku(self, value):
        if not value:
            return value
        if Product.objects.filter(sku=value).exists():
            if self.instance and self.instance.sku == value:
                return value
            raise serializers.ValidationError('SKU must be unique')
        return value

    def validate_price(self, value):
        if value < 0:
            raise serializers.ValidationError('Price cannot be negative')
        return value

