import time
import logging
from django.utils.deprecation import MiddlewareMixin
from django.http import JsonResponse

logger = logging.getLogger(__name__)

class RequestLoggingMiddleware(MiddlewareMixin):
    """Log all requests with timing and user info."""

    def process_request(self, request):
        request.start_time = time.time()
        return None

    def process_response(self, request, response):
        if not hasattr(request, 'start_time'):
            return response

        duration = time.time() - request.start_time
        duration_ms = round(duration * 1000, 2)

        user = getattr(request, 'user', None)
        user_str = user.username if user and user.is_authenticated else 'anonymous'

        log_data = {
            'method': request.method,
            'path': request.path,
            'status': response.status_code,
            'duration_ms': duration_ms,
            'user': user_str,
            'ip': self.get_client_ip(request),
        }

        if response.status_code >= 500:
            logger.error('Server error', extra=log_data)
        elif response.status_code >= 400:
            logger.warning('Client error', extra=log_data)
        else:
            logger.info('Request processed', extra=log_data)

        # Add timing header
        response['X-Request-Duration'] = f'{duration_ms}ms'
        return response

    def get_client_ip(self, request):
        x_forwarded_for = request.META.get('HTTP_X_FORWARDED_FOR')
        if x_forwarded_for:
            ip = x_forwarded_for.split(',')[0].strip()
        else:
            ip = request.META.get('REMOTE_ADDR')
        return ip

class CORSMiddleware(MiddlewareMixin):
    """Simple CORS middleware for API endpoints."""

    def __init__(self, get_response=None):
        super().__init__(get_response)
        self.allowed_origins = ['http://localhost:3000', 'http://127.0.0.1:3000']
        self.allowed_methods = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS']
        self.allowed_headers = ['Content-Type', 'Authorization', 'X-Requested-With']

    def process_request(self, request):
        if request.method == 'OPTIONS':
            return self.handle_preflight(request)
        return None

    def process_response(self, request, response):
        origin = request.META.get('HTTP_ORIGIN')

        if origin in self.allowed_origins or '*' in self.allowed_origins:
            response['Access-Control-Allow-Origin'] = origin
            response['Access-Control-Allow-Methods'] = ', '.join(self.allowed_methods)
            response['Access-Control-Allow-Headers'] = ', '.join(self.allowed_headers)
            response['Access-Control-Allow-Credentials'] = 'true'

        return response

    def handle_preflight(self, request):
        response = JsonResponse({})
        response.status_code = 200
        return response

class RateLimitMiddleware(MiddlewareMixin):
    """Simple rate limiting middleware."""

    def __init__(self, get_response=None):
        super().__init__(get_response)
        self.requests = {}
        self.limit = 100  # requests per window
        self.window = 60  # seconds

    def process_request(self, request):
        # Skip rate limiting for authenticated users
        if hasattr(request, 'user') and request.user.is_authenticated:
            return None

        ip = self.get_client_ip(request)
        now = time.time()

        # Clean old entries
        self.requests = {
            k: v for k, v in self.requests.items()
            if v['reset_time'] > now
        }

        # Check current IP
        if ip not in self.requests:
            self.requests[ip] = {
                'count': 0,
                'reset_time': now + self.window
            }

        self.requests[ip]['count'] += 1

        if self.requests[ip]['count'] > self.limit:
            return JsonResponse(
                {'error': 'Rate limit exceeded'},
                status=429
            )

        return None

    def get_client_ip(self, request):
        x_forwarded_for = request.META.get('HTTP_X_FORWARDED_FOR')
        if x_forwarded_for:
            return x_forwarded_for.split(',')[0].strip()
        return request.META.get('REMOTE_ADDR')

